              type="button"
              role="tab"
              aria-selected={active === i}
              aria-controls="testimonials-panel"
              aria-label={`Show ${t.company} testimonial`}
              onClick={() => setActive(i)}
              className="group flex min-h-12 cursor-pointer items-center justify-center rounded-full px-1 outline-none transition focus-visible:ring-2 focus-visible:ring-(--testimonial-fg) focus-visible:ring-offset-4 focus-visible:ring-offset-(--testimonial-bg)"
            >
              <span
                className={`flex h-10 w-36 items-center justify-center transition duration-200 sm:w-40 [&_img]:max-h-8 [&_img]:max-w-full [&_img]:object-contain ${active === i ? "opacity-100" : "opacity-40 group-hover:opacity-70"}`}
              >
                <Image
                  src={t.logo}
                  alt={t.company}
                  width={t.logoWidth}
                  height={t.logoHeight}
                  className="max-h-8 w-auto object-contain"
                />
              </span>
            </button>
          ))}
        </div>

        {/* Testimonial panel */}
        <figure
          id="testimonials-panel"
          role="tabpanel"
          aria-live="polite"
          className="relative mx-auto mt-16 min-h-96 max-w-5xl text-center sm:mt-20 sm:min-h-112 lg:min-h-128"
        >
          {testimonials.map((t, i) => (
            <div
              key={t.company}
              aria-hidden={active !== i}
              className={`absolute inset-0 flex flex-col items-center justify-start transition-opacity duration-500 ease-out motion-reduce:transition-none ${active === i ? "opacity-100" : "pointer-events-none opacity-0"}`}
            >
              <blockquote
                className="font-display mx-auto max-w-5xl text-balance text-4xl/[1.12] font-normal tracking-tight text-(--testimonial-fg) sm:text-5xl/[1.08] lg:text-[4.5rem]/[1.05] *:first:before:content-['“'] *:last:after:content-['”']"
              >
                <p>{t.quote}</p>
              </blockquote>
              <figcaption className="mt-16 text-base/7 text-(--testimonial-muted) sm:text-lg/8">
                <span className="font-semibold text-(--testimonial-fg)">{t.author}</span>
                <span>, {t.role}</span>
              </figcaption>
            </div>
          ))}
        </figure>
      </div>
    </section>
  );
}

"use client";

import { useState, useEffect, useCallback } from "react";
import Image from "next/image";
import Link from "next/link";
import PlayIcon from "./icons/PlayIcon";
import ArrowRightIcon from "./icons/ArrowRightIcon";
import XMarkIcon from "./icons/XMarkIcon";

const YOUTUBE_ID = "eRsoRbJs8O0";

export default function OpenSource() {
  const [open, setOpen] = useState(false);

  const close = useCallback(() => setOpen(false), []);

  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === "Escape") close();
    };
    document.addEventListener("keydown", onKey);
    document.body.classList.add("overflow-hidden");
    return () => {
      document.removeEventListener("keydown", onKey);
      document.body.classList.remove("overflow-hidden");
    };
  }, [open, close]);

  return (
    <section className="py-16" id="open-source">
      <div className="mx-auto flex w-full max-w-(--content-max-width) flex-col gap-10 px-6 sm:gap-16 lg:px-10">
        <div className="flex max-w-2xl flex-col gap-6">
          <div className="flex flex-col gap-2">
            <div className="font-mono text-xs/7 font-medium uppercase tracking-widest text-(--color-text-secondary)">
              Open-source
            </div>
            <h2 className="text-pretty text-[clamp(1.75rem,3.5vw,calc(var(--heading-size)*0.7))] leading-[1.15] text-(--color-text) font-display [font-weight:var(--heading-weight)] [letter-spacing:var(--heading-letter-spacing)]">
              Warp Terminal is now open-source
            </h2>
          </div>
          <div className="text-pretty text-(length:--body-size) leading-(--body-line-height) text-(--color-text-secondary)">
            <p>
              We&apos;re excited to build Warp alongside the community using an open-first workflow
              managed by Oz, our cloud agent orchestration platform.
            </p>
          </div>
          <div className="flex w-full flex-col items-stretch gap-4 sm:w-auto sm:flex-row sm:items-center">
            <Link
              href="/blog/warp-is-now-open-source"
              className="btn-hover inline-flex h-11 w-full shrink-0 items-center justify-center gap-1.5 rounded-(--btn-radius) bg-(--btn-bg) p-(--btn-padding) text-sm/7 font-medium text-(--btn-text-color) [border:var(--btn-border)] hover:opacity-85 sm:w-auto"
            >
              Read more
              <ArrowRightIcon className="size-3.5" />
            </Link>
          </div>
        </div>

        <button
          type="button"
          onClick={() => setOpen(true)}
          aria-label="Play video: Warp Terminal is now open-source"
          aria-haspopup="dialog"
          className="group/video relative block aspect-video w-full cursor-pointer overflow-hidden rounded-(--img-radius) border-0 bg-(--color-surface) p-0 text-inherit"
        >
          <div className="absolute inset-0 *:size-full *:object-cover">
            <Image
              src="/images/open-source-poster.jpg"
              alt="Warp open-source announcement video poster"
              fill
              className="object-cover"
              sizes="100vw"
              quality={90}
            />
          </div>
          <span aria-hidden="true" className="absolute inset-0 bg-linear-to-t from-black/25 via-transparent to-transparent" />
          <span aria-hidden="true" className="pointer-events-none absolute inset-0 flex items-center justify-center">
            <span className="flex size-16 items-center justify-center rounded-full bg-white/95 text-black shadow-xl transition-transform duration-200 ease-out group-hover/video:scale-110">
              <PlayIcon className="size-6 translate-x-px" />
            </span>
          </span>
        </button>
      </div>

      {open && (
        <div
          role="dialog"
          aria-modal="true"
          aria-label="Warp Terminal is now open-source"
          className="fixed inset-0 z-9999 flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 sm:p-8 animate-[fade-in_150ms_ease-out]"
        >
          <button
            type="button"
            onClick={close}
            aria-label="Close video"
            className="absolute inset-0 cursor-default"
          />
          <button
            type="button"
            onClick={close}
            aria-label="Close video"
            className="absolute right-4 top-4 z-10 inline-flex size-10 items-center justify-center rounded-full bg-white/10 text-white backdrop-blur-md transition-colors hover:bg-white/20 sm:right-6 sm:top-6"
          >
            <XMarkIcon className="size-5" />
          </button>
          <div className="relative z-10 aspect-video w-full max-w-6xl overflow-hidden rounded-(--img-radius) bg-black shadow-2xl">
            <iframe
              src={`https://www.youtube.com/embed/${YOUTUBE_ID}?autoplay=1&rel=0`}
              title="Warp Terminal is now open-source"
              allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
              allowFullScreen
              className="size-full border-0"
            />
          </div>
        </div>
      )}
    </section>
  );
}

"use client";

import { useState } from "react";
import Link from "next/link";
import CopyIcon from "./icons/CopyIcon";
import CheckmarkIcon from "./icons/CheckmarkIcon";
import AppleIcon from "./icons/AppleIcon";
import WindowsIcon from "./icons/WindowsIcon";
import LinuxIcon from "./icons/LinuxIcon";

function CopyCommand({ command, id }: { command: string; id: string }) {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(command);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch { /* silent */ }
  };

  return (
    <div className="flex items-center justify-between gap-6 rounded-full bg-(--color-surface) p-1 font-mono text-sm/7 text-(--color-text-secondary) inset-ring-1 inset-ring-border">
      <div className="flex items-center gap-2 pl-3">
        <div className="select-none text-current/60">$</div>
        <span className="normal-case tracking-normal" id={id}>{command}</span>
      </div>
      <button
        type="button"
        onClick={handleCopy}
        className="group relative flex size-9 items-center justify-center rounded-full after:pointer-fine:hidden after:absolute after:-inset-1 hover:bg-(--color-border)"
        aria-label={`Copy: ${command}`}
      >
        {copied ? <CheckmarkIcon /> : <CopyIcon />}
      </button>
    </div>
  );
}

function PkgLinks({ items }: { items: { label: string; href: string }[] }) {
  return (
    <div className="flex items-center gap-2">
      {items.map((item) => (
        <a
          key={item.href}
          href={item.href}
          className="inline-flex items-center justify-center rounded-lg bg-text/10 px-3 py-1 text-xs/5 font-medium text-(--color-text) transition-colors hover:bg-text/20"
        >
          {item.label}
        </a>
      ))}
    </div>
  );
}

function PackageRow({ name, sub, pkgs }: { name: string; sub?: string; pkgs: { label: string; href: string }[] }) {
  return (
    <div className="py-3 first:pt-0 last:pb-0">
      <div className="flex items-center justify-between gap-3">
        <div className="flex items-baseline gap-2">
          <span className="text-sm/7 font-medium text-(--color-text)">{name}</span>
          {sub && <span className="text-xs/5 text-(--color-text-secondary)">{sub}</span>}
        </div>
        <PkgLinks items={pkgs} />
      </div>
    </div>
  );
}

const h2HeadingClassName = "text-(--color-text) text-[clamp(1.75rem,3.5vw,calc(var(--heading-size)_*_0.7))] leading-[1.15] [font-family:var(--font-heading)] [font-weight:var(--heading-weight)] [letter-spacing:var(--heading-letter-spacing)]";

const headingClassName = "text-(--color-text) text-[clamp(1.25rem,2.5vw,1.5rem)] leading-[1.2] [font-family:var(--font-heading)] [font-weight:var(--heading-weight)] [letter-spacing:var(--heading-letter-spacing)]";

export default function Downloads() {
